{
  "name": "Service App Pro",
  "description": "A professional service management application with monthly tracking, financial summaries, and Excel export capabilities. Designed with a sleek navy blue theme for mobile and desktop."
}

export type PaymentMethod = 'Pix' | 'Cartão' | 'Dinheiro' | 'Transferência';

export interface ServiceRecord {
  id: string;
  clientName: string;
  description: string;
  value: number;
  paymentMethod: PaymentMethod;
  date: string; // ISO string
}

export interface User {
  id: string;
  username: string;
  isAuthenticated: boolean;
}

export interface MonthlyGroup {
  monthYear: string; // Format: "Janeiro 2024"
  services: ServiceRecord[];
  totalValue: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { LogIn, Plus, LogOut, FileSpreadsheet, Send, Search, Filter } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, PaymentMethod, MonthlyGroup, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_app_data';
const AUTH_KEY = 'service_app_auth';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isBackupLoading, setIsBackupLoading] = useState(false);

  // Load data on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    const savedAuth = localStorage.getItem(AUTH_KEY);

    if (savedData) {
      setServices(JSON.parse(savedData));
    }
    if (savedAuth) {
      setUser(JSON.parse(savedAuth));
    }
  }, []);

  // Save data whenever services change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: '1', username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem(AUTH_KEY);
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: crypto.randomUUID() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Deseja excluir este serviço?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + curr.value, 0);
  }, [services]);

  const exportToExcel = () => {
    const worksheetData = services.map(s => ({
      Data: new Date(s.date).toLocaleDateString('pt-BR'),
      Cliente: s.clientName,
      Serviço: s.description,
      Valor: s.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }),
      'Forma de Pagamento': s.paymentMethod
    }));

    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Serviços");

    // Save locally
    XLSX.writeFile(workbook, "Relatorio_Servicos.xlsx");

    return workbook;
  };

  const handleBackupAndEmail = async () => {
    setIsBackupLoading(true);
    try {
      // 1. Export Excel
      exportToExcel();

      // 2. Simulate email sending logic
      // In a real frontend-only environment, we use mailto or an API.
      // Since automated email with attachments usually requires a backend,
      // we'll provide a mailto link with the summary data.
      const email = 'layannefranca1@gmail.com';
      const subject = encodeURIComponent('Backup de Serviços - Service App');
      const body = encodeURIComponent(
        `Olá,\n\nSegue o backup dos serviços realizados.\nTotal Acumulado: R$ ${totalAccumulated.toFixed(2)}\nTotal de Registros: ${services.length}\n\nO arquivo Excel foi baixado automaticamente em seu dispositivo.`
      );

      // Artificial delay for better UX
      await new Promise(resolve => setTimeout(resolve, 1500));

      window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;

      alert('Backup gerado e e-mail de notificação preparado!');
    } catch (error) {
      console.error('Backup error:', error);
      alert('Ocorreu um erro ao realizar o backup.');
    } finally {
      setIsBackupLoading(false);
    }
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white pb-20">
      {/* Header */}
      <header className="sticky top-0 z-40 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div>
            <h1 className="text-xl font-bold tracking-tight">Service App</h1>
            <p className="text-xs text-slate-400">Olá, {user.username}</p>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleBackupAndEmail}
              disabled={isBackupLoading}
              className="p-2 bg-emerald-600 hover:bg-emerald-500 rounded-lg transition-colors flex items-center gap-2 text-sm disabled:opacity-50"
              title="Backup para Excel e Email"
            >
              {isBackupLoading ? <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full" /> : <FileSpreadsheet size={18} />}
              <span className="hidden sm:inline">Backup</span>
            </button>
            <button 
              onClick={handleLogout}
              className="p-2 bg-slate-800 hover:bg-slate-700 rounded-lg transition-colors"
            >
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6">
        {/* Summary Dashboard */}
        <DashboardStats total={totalAccumulated} count={services.length} />

        {/* Services List grouped by month */}
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h2 className="text-lg font-semibold flex items-center gap-2">
              <Filter size={18} className="text-blue-400" />
              Histórico de Serviços
            </h2>
          </div>

          {services.length === 0 ? (
            <div className="text-center py-12 bg-slate-900/50 border border-dashed border-slate-800 rounded-2xl">
              <p className="text-slate-500">Nenhum serviço cadastrado ainda.</p>
              <button 
                onClick={() => setIsFormOpen(true)}
                className="mt-4 text-blue-400 hover:text-blue-300 text-sm font-medium"
              >
                Clique no botão + para começar
              </button>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      {/* Floating Action Button */}
      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 hover:bg-blue-500 rounded-full flex items-center justify-center shadow-lg shadow-blue-500/20 active:scale-95 transition-all z-50"
      >
        <Plus size={32} />
      </button>

      {/* Modal Form */}
      {isFormOpen && (
        <ServiceForm 
          onClose={() => setIsFormOpen(false)} 
          onSubmit={addService} 
        />
      )}
    </div>
  );
};

export default App;

