export default ServiceForm;

import React from 'react';
import { Trash2, CalendarDays, Wallet } from 'lucide-react';
import { ServiceRecord, MonthlyGroup } from '../types';

interface ServiceListProps {
  services: ServiceRecord[];
  onDelete: (id: string) => void;
}

const ServiceList: React.FC<ServiceListProps> = ({ services, onDelete }) => {
  // Group services by month
  const grouped = services.reduce((acc: MonthlyGroup[], curr) => {
    const date = new Date(curr.date);
    const monthYear = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

    let group = acc.find(g => g.monthYear === monthYear);
    if (!group) {
      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }

    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  // Sort groups by date (newest first)
  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date);
    const dateB = new Date(b.services[0].date);
    return dateB.getTime() - dateA.getTime();
  });

  return (
    <div className="space-y-8">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-3">
          <div className="flex items-center justify-between sticky top-[72px] bg-slate-950/90 backdrop-blur-sm py-2 z-30">
            <h3 className="text-sm font-bold uppercase tracking-widest text-blue-400 flex items-center gap-2">
              <CalendarDays size={16} />
              {group.monthYear}
            </h3>
            <div className="bg-slate-900 border border-slate-800 px-3 py-1 rounded-full flex items-center gap-2">
              <span className="text-xs text-slate-500 font-medium">Total do Mês:</span>
              <span className="text-xs font-bold text-emerald-400">
                {group.totalValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
              </span>
            </div>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {group.services.map(service => (
              <div 
                key={service.id} 
                className="group relative bg-slate-900/40 hover:bg-slate-900 border border-slate-800 rounded-2xl p-4 transition-all duration-200"
              >
                <div className="flex justify-between items-start">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <span className="text-blue-400 text-xs font-bold uppercase tracking-tighter">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="w-1 h-1 bg-slate-700 rounded-full" />
                      <span className="text-slate-500 text-xs font-medium bg-slate-800 px-2 py-0.5 rounded-full">
                        {service.paymentMethod}
                      </span>
                    </div>
                    <h4 className="font-bold text-slate-100">{service.clientName}</h4>
                    <p className="text-sm text-slate-400 line-clamp-2">{service.description}</p>
                  </div>

                  <div className="text-right">
                    <p className="text-lg font-bold text-white">
                      {service.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    <button 
                      onClick={() => onDelete(service.id)}
                      className="mt-2 p-2 text-slate-600 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default ServiceList;

