const STORAGE_KEY = 'service_app_data_v2';
const AUTH_KEY = 'service_app_auth_v2';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isBackupLoading, setIsBackupLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper para gerar ID único com fallback
  const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    return Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
  };

  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    const savedAuth = localStorage.getItem(AUTH_KEY);

    if (savedData) {
      try {
        setServices(JSON.parse(savedData));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
    if (savedAuth) {
      setUser(JSON.parse(savedAuth));
    }
  }, []);

  useEffect(() => {
    if (services.length > 0 || localStorage.getItem(STORAGE_KEY)) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
    }
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: '1', username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da conta?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: generateId() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir este registro permanentemente?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + curr.value, 0);
  }, [services]);

  const handleExport = () => {
    if (services.length === 0) return alert('Não há dados para exportar.');

    // 1. Excel Export
    const worksheetData = services.map(s => ({
      Data: new Date(s.date).toLocaleDateString('pt-BR'),
      Cliente: s.clientName,
      Serviço: s.description,
      Valor: s.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }),
      'Forma de Pagamento': s.paymentMethod
    }));

    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Serviços");
    XLSX.writeFile(workbook, `Servicos_Backup_${new Date().toISOString().split('T')[0]}.xlsx`);

    // 2. JSON Backup (Para sincronizar entre dispositivos)
    const backup: BackupData = {
      services,
      version: '2.0',
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(backup)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Sincronizacao_App_${new Date().getTime()}.json`;
    a.click();

    // 3. Email Notification
    const email = 'layannefranca1@gmail.com';
    const subject = encodeURIComponent('Relatório de Serviços - Service App');
    const body = encodeURIComponent(
      `Relatório Gerado em: ${new Date().toLocaleString('pt-BR')}\n\n` +
      `Total Acumulado: R$ ${totalAccumulated.toFixed(2)}\n` +
      `Quantidade de Serviços: ${services.length}\n\n` +
      `Os arquivos de backup (Excel e JSON) foram baixados em seu dispositivo para segurança e sincronização.`
    );
    window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;
  };

  const handleImportClick = () => fileInputRef.current?.click();

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const data = JSON.parse(content) as BackupData;
        if (data.services && Array.isArray(data.services)) {
          if (window.confirm(`Deseja importar ${data.services.length} registros? Isso substituirá os dados atuais.`)) {
            setServices(data.services);
            alert('Dados importados com sucesso!');
          }
        }
      } catch (err) {
        alert('Arquivo inválido. Certifique-se de usar o arquivo .json gerado pelo app.');
      }
    };
    reader.readAsText(file);
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white pb-24 selection:bg-blue-500/30">
      {/* Header Mobile & Desktop */}
      <header className="sticky top-0 z-40 bg-slate-900/90 backdrop-blur-xl border-b border-slate-800/50 p-4 shadow-lg shadow-black/20">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-600/20">
              <Briefcase size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold leading-tight">Service App</h1>
              <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Pro Edition</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleExport}
              className="p-2.5 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-xl transition-all border border-blue-500/20"
              title="Exportar para Excel e Email"
            >
              <Download size={20} />
            </button>
            <button 
              onClick={handleImportClick}
              className="p-2.5 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-xl transition-all border border-slate-700"
              title="Sincronizar outro dispositivo"
            >
              <Upload size={20} />
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileImport} 
              accept=".json" 
              className="hidden" 
            />
            <button 
              onClick={handleLogout}
              className="p-2.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-xl transition-all border border-red-500/10"
            >
              <LogOut size={20} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6">
        {/* Dashboard de Valores */}
        <DashboardStats total={totalAccumulated} count={services.length} />

        {/* Lista de Serviços Agrupados */}
        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
              <Filter size={14} className="text-blue-500" />
              Histórico Mensal
            </h2>
          </div>

          {services.length === 0 ? (
            <div className="text-center py-20 bg-slate-900/30 border-2 border-dashed border-slate-800/50 rounded-[32px] flex flex-col items-center">
              <div className="w-16 h-16 bg-slate-800/50 rounded-full flex items-center justify-center mb-4">
                <Plus size={32} className="text-slate-600" />
              </div>
              <p className="text-slate-500 font-medium">Nenhum serviço registrado.</p>
              <button 
                onClick={() => setIsFormOpen(true)}
                className="mt-4 text-blue-400 hover:text-blue-300 text-sm font-bold bg-blue-500/10 px-6 py-2 rounded-full border border-blue-500/20"
              >
                Adicionar Primeiro Serviço
              </button>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      {/* Botão Flutuante Principal */}
      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-blue-600 hover:bg-blue-500 text-white rounded-[24px] flex items-center justify-center shadow-2xl shadow-blue-600/40 active:scale-90 transition-all z-50 animate-bounce-subtle"
      >
        <Plus size={32} />
      </button>

      {/* Modal de Cadastro */}
      {isFormOpen && (
        <ServiceForm 
          onClose={() => setIsFormOpen(false)} 
          onSubmit={addService} 
        />
      )}

      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 3s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Mail, Lock, UserPlus, LogIn, CheckCircle2, Circle } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
}

interface StoredUser {
  email: string;
  password: string;
}

const USERS_STORAGE_KEY = 'service_app_registered_users_v2';
const REMEMBERED_CREDENTIALS_KEY = 'service_app_remembered_v2';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    const remembered = localStorage.getItem(REMEMBERED_CREDENTIALS_KEY);
    if (remembered) {
      try {
        const { email: savedEmail, password: savedPassword } = JSON.parse(remembered);
        setEmail(savedEmail);
        setPassword(savedPassword);
        setRememberMe(true);
      } catch (e) {
        console.error("Erro ao carregar lembranças", e);
      }
    }
  }, []);

  const getRegisteredUsers = (): StoredUser[] => {
    const users = localStorage.getItem(USERS_STORAGE_KEY);
    // Usuário padrão solicitado
    const defaultUser = { email: 'layannefranca1@gmail.com', password: '123' };
    return users ? JSON.parse(users) : [defaultUser];
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    const users = getRegisteredUsers();
    const user = users.find(u => u.email === email && u.password === password);

    if (user) {
      if (rememberMe) {
        localStorage.setItem(REMEMBERED_CREDENTIALS_KEY, JSON.stringify({ email, password }));
      } else {
        localStorage.removeItem(REMEMBERED_CREDENTIALS_KEY);
      }
      onLogin(user.email);
    } else {
      setError('E-mail ou senha incorretos.');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (password !== confirmPassword) return setError('As senhas não coincidem.');
    if (password.length < 3) return setError('Senha muito curta.');

    const users = getRegisteredUsers();
    if (users.find(u => u.email === email)) return setError('Este e-mail já existe.');

    const newUsers = [...users, { email, password }];
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(newUsers));

    setSuccess('Conta criada! Faça login agora.');
    setIsRegistering(false);
    setPassword('');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950 p-6 selection:bg-blue-500/30">
      <div className="w-full max-w-md bg-slate-900 border border-slate-800/50 p-8 rounded-[40px] shadow-2xl relative overflow-hidden">
        {/* Decorative background element */}
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-blue-600/10 blur-[100px] rounded-full"></div>

        <div className="flex flex-col items-center mb-10 relative z-10">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-[28px] flex items-center justify-center mb-6 shadow-xl shadow-blue-600/20">
            {isRegistering ? <UserPlus size={36} className="text-white" /> : <ShieldCheck size={36} className="text-white" />}
          </div>
          <h1 className="text-3xl font-black tracking-tight text-white mb-2">Service App</h1>
          <p className="text-slate-400 text-sm font-medium">
            {isRegistering ? 'Crie seu novo acesso' : 'Bem-vindo(a) de volta'}
          </p>
        </div>

        {success && (
          <div className="mb-6 p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl text-emerald-400 text-sm text-center font-bold">
            {success}
          </div>
        )}

        <form onSubmit={isRegistering ? handleRegister : handleLogin} className="space-y-5 relative z-10">
          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">E-mail</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} />
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="seu@email.com"
                className="w-full bg-slate-800/50 border border-slate-700/50 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Senha</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} />
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                className="w-full bg-slate-800/50 border border-slate-700/50 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600"
                required
              />
            </div>
          </div>

          {isRegistering && (
            <div className="space-y-2 animate-in fade-in slide-in-from-top-2">
              <label className="text-xs font-bold text-slate-500 uppercase tracking-widest ml-1">Confirmar Senha</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} />
                <input
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full bg-slate-800/50 border border-slate-700/50 rounded-2xl py-4 pl-12 pr-4 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600"
                  required
                />
              </div>
            </div>
          )}

          {!isRegistering && (
            <button
              type="button"
              onClick={() => setRememberMe(!rememberMe)}
              className="flex items-center gap-2 text-sm text-slate-400 hover:text-slate-200 transition-colors py-2 ml-1"
            >
              {rememberMe ? (
                <CheckCircle2 size={20} className="text-blue-500" />
              ) : (
                <Circle size={20} className="text-slate-700" />
              )}
              Lembrar meu acesso
            </button>
          )}

          {error && <p className="text-red-400 text-xs text-center font-bold bg-red-500/10 py-2 rounded-lg">{error}</p>}

          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-4 rounded-2xl shadow-xl shadow-blue-600/20 transition-all active:scale-[0.98] flex items-center justify-center gap-3 text-lg mt-4"
          >
            {isRegistering ? <UserPlus size={20} /> : <LogIn size={20} />}
            {isRegistering ? 'Criar Conta' : 'Entrar Agora'}
          </button>
        </form>

        <div className="mt-10 text-center relative z-10 border-t border-slate-800/50 pt-8">
          <button
            onClick={() => {
              setIsRegistering(!isRegistering);
              setError('');
              setSuccess('');
            }}
            className="text-slate-500 hover:text-blue-400 text-sm font-bold transition-colors"
          >
            {isRegistering ? 'Já tem uma conta? Acesse' : 'Novo por aqui? Cadastre-se'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;

