import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Download, Upload, Filter, Briefcase } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User, BackupData } from './types.ts';
import Login from './components/Login.tsx';
import ServiceForm from './components/ServiceForm.tsx';
import ServiceList from './components/ServiceList.tsx';
import DashboardStats from './components/DashboardStats.tsx';

const STORAGE_KEY = 'service_app_data_v3';
const AUTH_KEY = 'service_app_auth_v3';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const generateId = () => {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID();
    }
    return Math.random().toString(36).substring(2, 15);
  };

  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    const savedAuth = localStorage.getItem(AUTH_KEY);

    if (savedData) {
      try {
        setServices(JSON.parse(savedData));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
    if (savedAuth) {
      setUser(JSON.parse(savedAuth));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: '1', username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da conta?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: generateId() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir este registro permanentemente?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + curr.value, 0);
  }, [services]);

  const handleExport = () => {
    if (services.length === 0) return alert('Não há dados para exportar.');

    // Excel
    const worksheetData = services.map(s => ({
      Data: new Date(s.date).toLocaleDateString('pt-BR'),
      Cliente: s.clientName,
      Serviço: s.description,
      Valor: s.value,
      'Pagamento': s.paymentMethod
    }));
    const worksheet = XLSX.utils.json_to_sheet(worksheetData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Serviços");
    XLSX.writeFile(workbook, `Backup_Servicos.xlsx`);

    // JSON para sincronizar
    const backup: BackupData = {
      services,
      version: '3.0',
      exportDate: new Date().toISOString()
    };
    const blob = new Blob([JSON.stringify(backup)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Sincronizacao.json`;
    a.click();

    // Email
    const email = 'layannefranca1@gmail.com';
    const subject = encodeURIComponent('Relatório de Serviços - Service App');
    const body = encodeURIComponent(
      `Relatório de Serviços\n\nTotal Acumulado: R$ ${totalAccumulated.toFixed(2)}\nTotal de Serviços: ${services.length}\n\nOs arquivos de Excel e JSON foram gerados para backup.`
    );
    window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.services) {
          if (confirm('Importar registros? Isso substituirá os atuais.')) {
            setServices(data.services);
          }
        }
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-24">
      <header className="sticky top-0 z-40 bg-slate-900/80 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center">
              <Briefcase size={22} />
            </div>
            <h1 className="text-xl font-bold">Service App</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={handleExport} className="p-2.5 bg-blue-600/20 text-blue-400 rounded-xl border border-blue-500/20"><Download size={20} /></button>
            <button onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-slate-800 text-slate-300 rounded-xl border border-slate-700"><Upload size={20} /></button>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
            <button onClick={handleLogout} className="p-2.5 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10"><LogOut size={20} /></button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6">
        <DashboardStats total={totalAccumulated} count={services.length} />
        <div className="space-y-4">
          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 px-2">
            <Filter size={14} className="text-blue-500" />
            Histórico Mensal
          </h2>
          {services.length === 0 ? (
            <div className="text-center py-20 bg-slate-900/20 border-2 border-dashed border-slate-800 rounded-[32px] text-slate-500">
              Nenhum serviço registrado.
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      <button onClick={() => setIsFormOpen(true)} className="fixed bottom-8 right-6 w-16 h-16 bg-blue-600 text-white rounded-[24px] flex items-center justify-center shadow-2xl shadow-blue-600/40 active:scale-95 transition-all z-50">
        <Plus size={32} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React from 'react';
import { Trash2, CalendarDays, Wallet } from 'lucide-react';
import { ServiceRecord, MonthlyGroup } from '../types.ts';

interface ServiceListProps {
  services: ServiceRecord[];
  onDelete: (id: string) => void;
}

const ServiceList: React.FC<ServiceListProps> = ({ services, onDelete }) => {
  const grouped = services.reduce((acc: MonthlyGroup[], curr) => {
    const date = new Date(curr.date);
    const monthYear = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
    let group = acc.find(g => g.monthYear === monthYear);
    if (!group) {
      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }
    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date);
    const dateB = new Date(b.services[0].date);
    return dateB.getTime() - dateA.getTime();
  });

  return (
    <div className="space-y-12">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-4">
          <div className="flex items-center justify-between sticky top-[76px] bg-[#020617]/95 backdrop-blur-sm py-3 z-30">
            <h3 className="text-sm font-bold uppercase tracking-widest text-blue-400 flex items-center gap-2">
              <CalendarDays size={16} />
              {group.monthYear}
            </h3>
            <span className="text-[10px] text-slate-500 bg-slate-900 px-3 py-1 rounded-full border border-slate-800 font-bold uppercase">
              Início do Mês
            </span>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {group.services.map(service => (
              <div key={service.id} className="bg-slate-900/50 border border-slate-800 rounded-2xl p-4">
                <div className="flex justify-between items-start">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <span className="text-blue-400 text-[10px] font-black uppercase tracking-widest">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-slate-500 text-[10px] font-bold bg-slate-800 px-2 py-0.5 rounded-full border border-slate-700">
                        {service.paymentMethod}
                      </span>
                    </div>
                    <h4 className="font-bold text-white text-lg">{service.clientName}</h4>
                    <p className="text-sm text-slate-400">{service.description}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xl font-black text-white">
