import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Download, Upload, Filter, Briefcase } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User, BackupData } from './types.ts';
import Login from './components/Login.tsx';
import ServiceForm from './components/ServiceForm.tsx';
import ServiceList from './components/ServiceList.tsx';
import DashboardStats from './components/DashboardStats.tsx';

const STORAGE_KEY = 'service_app_v4_data';
const AUTH_KEY = 'service_app_v4_auth';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>([]);
  const [user, setUser] = useState<User | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Carregar dados iniciais
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    const savedAuth = localStorage.getItem(AUTH_KEY);

    if (savedData) {
      try {
        setServices(JSON.parse(savedData));
      } catch (e) {
        console.error("Erro ao carregar serviços", e);
      }
    }
    if (savedAuth) {
      setUser(JSON.parse(savedAuth));
    }
  }, []);

  // Salvar sempre que houver mudanças
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: '1', username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da sua conta?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: Math.random().toString(36).substring(2, 11) };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir este serviço?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + curr.value, 0);
  }, [services]);

  const handleExportAndBackup = () => {
    if (services.length === 0) return alert('Não há serviços para exportar.');

    // 1. Gerar Excel
    const worksheet = XLSX.utils.json_to_sheet(services.map(s => ({
      Data: new Date(s.date).toLocaleDateString('pt-BR'),
      Nome: s.clientName,
      Serviço: s.description,
      Valor: s.value,
      'Pagamento': s.paymentMethod
    })));
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Serviços");
    XLSX.writeFile(workbook, `Backup_Servicos_${new Date().toISOString().split('T')[0]}.xlsx`);

    // 2. Gerar JSON para sincronização entre dispositivos
    const backup: BackupData = { services, version: '4.0', exportDate: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(backup)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Sincronizacao_ServiceApp.json`;
    a.click();

    // 3. Email automático
    const email = 'layannefranca1@gmail.com';
    const subject = encodeURIComponent('Relatório de Serviços - Service App');
    const body = encodeURIComponent(
      `Relatório Gerado: ${new Date().toLocaleString('pt-BR')}\n` +
      `Total Acumulado: R$ ${totalAccumulated.toFixed(2)}\n` +
      `Quantidade: ${services.length}\n\n` +
      `O arquivo Excel foi gerado. Use o arquivo .json para sincronizar com outros dispositivos.`
    );
    window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = JSON.parse(event.target?.result as string);
        if (content.services && Array.isArray(content.services)) {
          if (confirm(`Deseja importar ${content.services.length} registros? Isso substituirá os atuais.`)) {
            setServices(content.services);
          }
        }
      } catch (err) {
        alert('Erro ao importar arquivo de sincronização.');
      }
    };
    reader.readAsText(file);
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-24 font-sans selection:bg-blue-500/30">
      {/* Navbar Superior */}
      <header className="sticky top-0 z-40 bg-slate-900/90 backdrop-blur-xl border-b border-slate-800 p-4 shadow-lg">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-600/20">
              <Briefcase size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-lg font-bold leading-tight">Service App</h1>
              <p className="text-[10px] text-slate-500 uppercase tracking-widest font-bold">Gerenciamento</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleExportAndBackup}
              className="p-2.5 bg-blue-600/20 text-blue-400 rounded-xl transition-all border border-blue-500/20 hover:bg-blue-600/30"
              title="Backup e Email"
            >
              <Download size={20} />
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-2.5 bg-slate-800 text-slate-300 rounded-xl transition-all border border-slate-700 hover:bg-slate-700"
              title="Sincronizar outro dispositivo"
            >
              <Upload size={20} />
            </button>
            <input type="file" ref={fileInputRef} onChange={handleImportFile} accept=".json" className="hidden" />
            <button 
              onClick={handleLogout}
              className="p-2.5 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 hover:bg-red-500/20 transition-all"
            >
              <LogOut size={20} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-500">
        {/* Valor Acumulado no Início */}
        <DashboardStats total={totalAccumulated} count={services.length} />

        <div className="space-y-4">
          <h2 className="text-xs font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2 px-2">
            <Filter size={14} className="text-blue-500" />
            Classificação Mensal
          </h2>

          {services.length === 0 ? (
            <div className="text-center py-20 bg-slate-900/30 border-2 border-dashed border-slate-800 rounded-[32px] text-slate-500 font-medium">
              Nenhum serviço cadastrado ainda.
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      {/* Botão Adicionar (Mobile Friendly) */}
      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-blue-600 hover:bg-blue-500 text-white rounded-[24px] flex items-center justify-center shadow-2xl shadow-blue-600/40 active:scale-90 transition-all z-50 animate-bounce-subtle"
      >
        <Plus size={32} />
      </button>

      {isFormOpen && (
        <ServiceForm 
          onClose={() => setIsFormOpen(false)} 
          onSubmit={addService} 
        />
      )}

      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 3s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';
import { Trash2, CalendarDays } from 'lucide-react';
import { ServiceRecord, MonthlyGroup } from '../types.ts';

interface ServiceListProps {
  services: ServiceRecord[];
  onDelete: (id: string) => void;
}

const ServiceList: React.FC<ServiceListProps> = ({ services, onDelete }) => {
  // Agrupar serviços por mês/ano
  const grouped = services.reduce((acc: MonthlyGroup[], curr) => {
    const date = new Date(curr.date);
    const monthYear = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

    let group = acc.find(g => g.monthYear === monthYear);
    if (!group) {
      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }
    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  // Ordenar grupos (mais recentes primeiro)
  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date).getTime();
    const dateB = new Date(b.services[0].date).getTime();
    return dateB - dateA;
  });

  return (
    <div className="space-y-10">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-4">
          <div className="flex items-center justify-between sticky top-[76px] bg-[#020617]/95 backdrop-blur-sm py-2 z-30">
            <h3 className="text-sm font-bold uppercase tracking-widest text-blue-400 flex items-center gap-2">
              <CalendarDays size={16} />
              {group.monthYear}
            </h3>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {group.services.map(service => (
              <div key={service.id} className="bg-slate-900/60 border border-slate-800 rounded-3xl p-5 hover:border-slate-700 transition-colors shadow-sm">
                <div className="flex justify-between items-start">
                  <div className="space-y-2">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-blue-500 text-[10px] font-black uppercase tracking-widest bg-blue-500/10 px-2 py-0.5 rounded-lg border border-blue-500/20">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-slate-400 text-[10px] font-bold bg-slate-800 px-2 py-0.5 rounded-lg border border-slate-700 uppercase">
                        {service.paymentMethod}
                      </span>
                    </div>
                    <h4 className="font-bold text-white text-lg leading-tight">{service.clientName}</h4>
                    <p className="text-sm text-slate-500 italic">{service.description}</p>
                  </div>
                  <div className="text-right flex flex-col items-end gap-3">
                    <p className="text-xl font-black text-white whitespace-nowrap">
                      {service.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    <button 
                      onClick={() => onDelete(service.id)} 
                      className="p-2 text-slate-600 hover:text-red-400 transition-colors bg-slate-800/50 rounded-xl"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Valor Total por Mês ao final da lista do mês */}
          <div className="bg-emerald-500/5 border border-emerald-500/20 rounded-2xl p-4 flex items-center justify-between">
            <span className="text-xs font-bold text-emerald-500/80 uppercase tracking-widest">Total de {group.monthYear}:</span>
            <span className="text-2xl font-black text-emerald-400">
              {group.totalValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
            </span>
          </div>
        </div>
      ))}
    </div>
  );
};

