      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }
    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date).getTime();
    const dateB = new Date(b.services[0].date).getTime();
    return dateB - dateA;
  });

  return (
    <div className="space-y-10">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-4">
          <div className="flex items-center justify-between sticky top-[76px] bg-[#020617]/95 backdrop-blur-sm py-2 z-30">
            <h3 className="text-xs font-black uppercase tracking-widest text-blue-400 flex items-center gap-2">
              <CalendarDays size={16} />
              {group.monthYear}
            </h3>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {group.services.map(service => (
              <div key={service.id} className="bg-slate-900/60 border border-slate-800 rounded-3xl p-5 shadow-sm">
                <div className="flex justify-between items-start">
                  <div className="space-y-2">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-blue-500 text-[10px] font-black uppercase tracking-widest bg-blue-500/10 px-2 py-0.5 rounded-lg border border-blue-500/20">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-slate-400 text-[10px] font-bold bg-slate-800 px-2 py-0.5 rounded-lg border border-slate-700 uppercase">
                        {service.paymentMethod}
                      </span>
                    </div>
                    <h4 className="font-bold text-white text-lg leading-tight">{service.clientName}</h4>
                    <p className="text-sm text-slate-500 italic">{service.description}</p>
                  </div>
                  <div className="text-right flex flex-col items-end gap-3">
                    <p className="text-xl font-black text-white whitespace-nowrap">
                      {service.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    <button onClick={() => onDelete(service.id)} className="p-2 text-slate-600 hover:text-red-400 transition-colors bg-slate-800/50 rounded-xl">
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="bg-emerald-500/5 border border-emerald-500/20 rounded-2xl p-4 flex items-center justify-between">
            <span className="text-[10px] font-black text-emerald-500/80 uppercase tracking-widest">Total {group.monthYear}:</span>
            <span className="text-2xl font-black text-emerald-400">
              {group.totalValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
            </span>
          </div>
        </div>
      ))}
    </div>
  );
};

