import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Download, Upload, Filter, Briefcase } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User, BackupData } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_app_v6_data';
const AUTH_KEY = 'service_app_v6_auth';

const App: React.FC = () => {
  // Estado de erro para depuração visual
  const [bootError, setBootError] = useState<string | null>(null);

  // Inicialização segura para serviços
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      if (typeof window !== 'undefined') {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
          const parsed = JSON.parse(saved);
          return Array.isArray(parsed) ? parsed : [];
        }
      }
    } catch (e) {
      console.error("Falha ao ler serviços do storage", e);
    }
    return [];
  });

  // Inicialização segura para usuário
  const [user, setUser] = useState<User | null>(() => {
    try {
      if (typeof window !== 'undefined') {
        const savedAuth = localStorage.getItem(AUTH_KEY);
        if (savedAuth) {
          return JSON.parse(savedAuth);
        }
      }
    } catch (e) {
      console.error("Falha ao ler auth do storage", e);
    }
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sincronizar storage
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
    } catch (e) {
      console.warn("Espaço de armazenamento cheio ou indisponível");
    }
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: 'user-' + Date.now(), username, isAuthenticated: true };
    setUser(newUser);
    try {
      localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
    } catch (e) {}
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da sua conta?')) {
      setUser(null);
      try {
        localStorage.removeItem(AUTH_KEY);
      } catch (e) {}
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { 
      ...data, 
      id: Math.random().toString(36).substring(2, 9) + Date.now() 
    };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir este serviço?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [services]);

  const handleExportAndBackup = () => {
    if (services.length === 0) return alert('Sem dados para exportar.');
    try {
      const ws = XLSX.utils.json_to_sheet(services.map(s => ({
        Data: new Date(s.date).toLocaleDateString('pt-BR'),
        Cliente: s.clientName,
        Servico: s.description,
        Valor: s.value,
        Pagamento: s.paymentMethod
      })));
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Servicos");
      XLSX.writeFile(wb, `Backup_Servicos.xlsx`);

      // Sincronização JSON
      const backup = JSON.stringify({ services, date: new Date().toISOString() });
      const blob = new Blob([backup], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = 'Sincronizacao.json';
      link.click();

      // Email
      const email = 'layannefranca1@gmail.com';
      const body = `Resumo: R$ ${totalAccumulated.toFixed(2)} em ${services.length} serviços.`;
      window.location.href = `mailto:${email}?subject=Backup Service App&body=${encodeURIComponent(body)}`;
    } catch (err) {
      alert("Erro ao exportar. Tente novamente.");
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target?.result as string);
        if (data.services) {
          setServices(data.services);
          alert('Dados importados com sucesso!');
        }
      } catch (e) {
        alert('Arquivo inválido.');
      }
    };
    reader.readAsText(file);
  };

  if (bootError) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-10 text-center">
        <div className="bg-red-500/10 border border-red-500/20 p-6 rounded-2xl">
          <p className="text-red-400 font-bold mb-2">Ocorreu um erro ao iniciar:</p>
          <code className="text-xs text-slate-500">{bootError}</code>
          <button onClick={() => window.location.reload()} className="block mx-auto mt-4 px-4 py-2 bg-slate-800 rounded-lg text-sm">Tentar Novamente</button>
        </div>
      </div>
    );
  }

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-24 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/90 backdrop-blur-md border-b border-slate-800 p-4">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg shadow-blue-600/20">
              <Briefcase size={22} />
            </div>
            <div>
              <h1 className="text-lg font-bold">Service App</h1>
              <p className="text-[10px] text-slate-500 font-black uppercase tracking-tighter">Gestão Profissional</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleExportAndBackup} className="p-2.5 bg-blue-600/20 text-blue-400 rounded-xl border border-blue-500/20"><Download size={20} /></button>
            <button onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-slate-800 text-slate-300 rounded-xl border border-slate-700"><Upload size={20} /></button>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
            <button onClick={handleLogout} className="p-2.5 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10"><LogOut size={20} /></button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-700">
        <DashboardStats total={totalAccumulated} count={services.length} />

        <div className="space-y-4">
          <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2 px-2">
            <Filter size={14} className="text-blue-500" />
            Classificação por Mês
          </h2>
          {services.length === 0 ? (
            <div className="text-center py-24 bg-slate-900/30 border border-slate-800 border-dashed rounded-[32px] text-slate-600">
              Nenhum registro encontrado.
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-blue-600 text-white rounded-[24px] flex items-center justify-center shadow-2xl shadow-blue-600/40 active:scale-95 transition-all z-50"
      >
        <Plus size={32} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Mail, Lock, UserPlus, LogIn, CheckCircle2, Circle } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
}

const USERS_KEY = 'service_app_users_v6';
const REMEMBER_KEY = 'service_app_remember_v6';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(REMEMBER_KEY);
      if (saved) {
        const { e, p } = JSON.parse(saved);
        setEmail(e);
        setPassword(p);
        setRememberMe(true);
      }
    } catch (e) {}
  }, []);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    try {
      const savedUsers = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
      const defaultUser = { email: 'layannefranca1@gmail.com', password: '123' };
      const allUsers = [defaultUser, ...savedUsers];

      if (isRegistering) {
        if (allUsers.find((u: any) => u.email === email)) {
          setError('Este e-mail já está cadastrado.');
          return;
        }
        const newUser = { email, password };
        localStorage.setItem(USERS_KEY, JSON.stringify([...savedUsers, newUser]));
        alert('Conta criada com sucesso!');
        setIsRegistering(false);
      } else {
        const found = allUsers.find((u: any) => u.email === email && u.password === password);
        if (found) {
          if (rememberMe) {
            localStorage.setItem(REMEMBER_KEY, JSON.stringify({ e: email, p: password }));
          } else {
            localStorage.removeItem(REMEMBER_KEY);
          }
          onLogin(email);
        } else {
          setError('E-mail ou senha incorretos.');
        }
      }
    } catch (err) {
      setError('Erro no sistema de login. Tente limpar os dados do navegador.');
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6">
      <div className="w-full max-w-md bg-slate-900/50 border border-slate-800 p-8 rounded-[40px] shadow-2xl relative overflow-hidden backdrop-blur-sm">
        <div className="absolute -top-20 -right-20 w-40 h-40 bg-blue-600/10 blur-[80px] rounded-full"></div>

        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mb-4 shadow-xl shadow-blue-600/20">
            <ShieldCheck size={32} />
          </div>
          <h1 className="text-2xl font-black text-white">Service App</h1>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">
            {isRegistering ? 'Cadastro' : 'Acesso Restrito'}
          </p>
        </div>

        <form onSubmit={handleAuth} className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">E-mail</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={16} />
              <input
                type="email"
                required
                value={email}
                onChange={e => setEmail(e.target.value)}
                className="w-full bg-slate-800/40 border border-slate-700/50 rounded-2xl py-3.5 pl-12 pr-4 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="seu@email.com"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-1">Senha</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={16} />
              <input
                type="password"
                required
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full bg-slate-800/40 border border-slate-700/50 rounded-2xl py-3.5 pl-12 pr-4 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="••••••••"
              />
            </div>
          </div>

          {!isRegistering && (
            <button type="button" onClick={() => setRememberMe(!rememberMe)} className="flex items-center gap-2 text-xs text-slate-500 hover:text-slate-300">
              {rememberMe ? <CheckCircle2 size={18} className="text-blue-500" /> : <Circle size={18} />}
              Lembrar acesso
            </button>
          )}

          {error && <p className="text-red-400 text-[10px] font-bold text-center bg-red-500/10 py-2 rounded-xl">{error}</p>}

          <button type="submit" className="w-full bg-blue-600 hover:bg-blue-500 py-4 rounded-2xl font-black text-white shadow-xl shadow-blue-600/20 active:scale-95 transition-all flex items-center justify-center gap-2">
            {isRegistering ? <UserPlus size={18} /> : <LogIn size={18} />}
            {isRegistering ? 'Criar Conta' : 'Entrar'}
          </button>
        </form>

        <button onClick={() => setIsRegistering(!isRegistering)} className="w-full mt-6 text-slate-500 hover:text-blue-400 text-xs font-bold transition-colors">
          {isRegistering ? 'Já tenho conta? Entrar' : 'Não tem conta? Cadastrar'}
        </button>
      </div>
    </div>
  );
};

