import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Download, Upload, Filter, Briefcase, Share2, Info } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_pro_v8_data';
const AUTH_KEY = 'service_pro_v8_auth';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        return Array.isArray(parsed) ? parsed : [];
      }
    } catch (e) { console.error(e); }
    return [];
  });

  const [user, setUser] = useState<User | null>(() => {
    try {
      const savedAuth = localStorage.getItem(AUTH_KEY);
      if (savedAuth) return JSON.parse(savedAuth);
    } catch (e) {}
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [showSyncInfo, setShowSyncInfo] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: 'user-' + Date.now(), username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (confirm('Deseja sair? Seus dados continuarão salvos neste aparelho.')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: Math.random().toString(36).substring(2, 9) + Date.now() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (confirm('Excluir este serviço?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [services]);

  const handleBackupAndSync = async () => {
    if (services.length === 0) return alert('Sem dados para sincronizar.');

    try {
      // 1. Gerar Excel para controle
      const ws = XLSX.utils.json_to_sheet(services.map(s => ({
        Data: new Date(s.date).toLocaleDateString('pt-BR'),
        Cliente: s.clientName,
        Serviço: s.description,
        Valor: s.value,
        Pagamento: s.paymentMethod
      })));
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Serviços");
      XLSX.writeFile(wb, `Backup_Servicos.xlsx`);

      // 2. Preparar arquivo de Sincronização JSON
      const syncData = JSON.stringify({ services, date: new Date().toISOString() });
      const fileName = `Sincronizacao_ServiceApp.json`;

      // Tentar usar o compartilhamento nativo do celular (WhatsApp/E-mail)
      if (navigator.share) {
        const file = new File([syncData], fileName, { type: 'application/json' });
        try {
          await navigator.share({
            title: 'Sincronização Service App',
            text: 'Envie este arquivo para o seu outro celular e use a opção IMPORTAR.',
            files: [file]
          });
        } catch (err) {
          // Fallback se o usuário cancelar ou o navegador não suportar arquivos no share
          downloadFile(syncData, fileName);
        }
      } else {
        downloadFile(syncData, fileName);
      }

      // 3. Enviar aviso por e-mail (conforme solicitado)
      const email = 'layannefranca1@gmail.com';
      const body = `Backup realizado!\n\nTotal de Serviços: ${services.length}\nValor Total: R$ ${totalAccumulated.toFixed(2)}`;
      window.location.href = `mailto:${email}?subject=Backup Service App&body=${encodeURIComponent(body)}`;

    } catch (err) {
      alert("Erro ao realizar backup. Tente baixar o arquivo manualmente.");
    }
  };

  const downloadFile = (content: string, name: string) => {
    const blob = new Blob([content], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = name;
    link.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target?.result as string);
        if (data && Array.isArray(data.services)) {
          const mode = confirm(`Encontrados ${data.services.length} serviços.\n\nClique em OK para ADICIONAR aos atuais.\nClique em CANCELAR para SUBSTITUIR tudo.`);
          if (mode) {
            // Merge sem duplicados simples
            setServices(prev => [...data.services, ...prev.filter(s => !data.services.find((d: any) => d.id === s.id))]);
          } else {
            setServices(data.services);
          }
          alert('Sincronização concluída!');
        }
      } catch (e) {
        alert('Arquivo inválido para sincronização.');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans overflow-x-hidden">
      {/* Header Premium */}
      <header className="sticky top-0 z-40 bg-slate-900/60 backdrop-blur-2xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Briefcase size={22} className="text-white" />
            </div>
            <div>
              <h1 className="text-lg font-black tracking-tight leading-none">Service App</h1>
              <p className="text-[9px] text-blue-400 font-black uppercase tracking-[0.2em] mt-1">Cloud Sync Ready</p>
            </div>
          </div>
          <div className="flex gap-1.5">
            <button onClick={() => setShowSyncInfo(true)} className="p-2.5 bg-slate-800 text-slate-400 rounded-xl hover:text-white transition-colors">
              <Info size={20} />
            </button>
            <button title="Backup e Sincronizar" onClick={handleBackupAndSync} className="p-2.5 bg-blue-600 text-white rounded-xl shadow-lg shadow-blue-600/30 hover:bg-blue-500 transition-all active:scale-90">
              <Share2 size={20} />
            </button>
            <button title="Importar de outro dispositivo" onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-emerald-500/10 text-emerald-500 rounded-xl border border-emerald-500/20 hover:bg-emerald-500/20">
              <Upload size={20} />
            </button>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
            <button title="Sair" onClick={handleLogout} className="p-2.5 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10">
              <LogOut size={20} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-8 pt-6 animate-in fade-in duration-500">
        <DashboardStats total={totalAccumulated} count={services.length} />

        <div className="space-y-6">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <Filter size={14} className="text-blue-500" />
              Histórico Mensal
            </h2>
          </div>

          {services.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 bg-slate-900/30 border border-white/5 border-dashed rounded-[40px] text-slate-600">
              <div className="w-16 h-16 bg-slate-800/50 rounded-full flex items-center justify-center mb-4">
                <Plus size={24} />
              </div>
              <p className="font-medium text-sm">Pronto para o primeiro serviço?</p>
              <p className="text-[10px] uppercase tracking-widest mt-2 opacity-50">Toque no botão azul abaixo</p>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      {/* Sync Info Modal */}
      {showSyncInfo && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-[#020617]/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-white/10 p-8 rounded-[40px] max-w-sm w-full shadow-3xl text-center space-y-6">
            <div className="w-20 h-20 bg-blue-600/10 rounded-full flex items-center justify-center mx-auto">
              <Share2 size={32} className="text-blue-500" />
            </div>
            <div>
              <h3 className="text-xl font-bold mb-2">Como usar em 2 aparelhos?</h3>
              <p className="text-slate-400 text-sm leading-relaxed">
                Como os dados são salvos localmente por segurança, para ver no outro celular:
                <br/><br/>
                1. No celular com os dados, clique em <span className="text-blue-500 font-bold">SINCRONIZAR (Botão Azul)</span>.<br/>
                2. Envie o arquivo para o outro celular.<br/>
                3. No outro celular, clique em <span className="text-emerald-500 font-bold">IMPORTAR (Botão Verde)</span> e selecione o arquivo.
              </p>
            </div>
            <button onClick={() => setShowSyncInfo(false)} className="w-full bg-slate-800 py-4 rounded-2xl font-bold">Entendi</button>
          </div>
        </div>
      )}

      {/* Float Action Button */}
      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-10 right-8 w-18 h-18 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[28px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-8 ring-[#020617]"
        style={{ width: '72px', height: '72px' }}
      >
        <Plus size={36} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Mail, Lock, UserPlus, LogIn, CheckCircle2, Circle, Smartphone } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
}

const USERS_KEY = 'service_app_users_v6';
const REMEMBER_KEY = 'service_app_remember_v6';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    try {
      const saved = localStorage.getItem(REMEMBER_KEY);
      if (saved) {
        const { e, p } = JSON.parse(saved);
        setEmail(e);
        setPassword(p);
        setRememberMe(true);
      }
    } catch (e) {}
  }, []);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    try {
      const savedUsers = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
      const defaultUser = { email: 'layannefranca1@gmail.com', password: '123' };
      const allUsers = [defaultUser, ...savedUsers];

      if (isRegistering) {
        if (allUsers.find((u: any) => u.email === email)) {
          setError('Este e-mail já está cadastrado.');
          return;
        }
        const newUser = { email, password };
        localStorage.setItem(USERS_KEY, JSON.stringify([...savedUsers, newUser]));
        alert('Conta criada com sucesso!');
        setIsRegistering(false);
      } else {
        const found = allUsers.find((u: any) => u.email === email && u.password === password);
        if (found) {
          if (rememberMe) {
            localStorage.setItem(REMEMBER_KEY, JSON.stringify({ e: email, p: password }));
          } else {
            localStorage.removeItem(REMEMBER_KEY);
          }
          onLogin(email);
        } else {
          setError('E-mail ou senha incorretos.');
        }
      }
    } catch (err) {
      setError('Erro no sistema de acesso.');
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 font-sans">
      <div className="w-full max-w-md bg-slate-900/40 border border-white/5 p-10 rounded-[48px] shadow-3xl relative overflow-hidden backdrop-blur-xl">
        {/* Background Accents */}
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-blue-600/20 blur-[100px] rounded-full"></div>
        <div className="absolute -bottom-24 -left-24 w-48 h-48 bg-indigo-600/10 blur-[100px] rounded-full"></div>

        <div className="flex flex-col items-center mb-10 relative">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[28px] flex items-center justify-center mb-6 shadow-2xl shadow-blue-500/30 ring-1 ring-white/20">
            <ShieldCheck size={40} className="text-white" />
          </div>
          <h1 className="text-3xl font-black text-white tracking-tight">Service App</h1>
          <p className="text-blue-500 text-[10px] font-black uppercase tracking-[0.4em] mt-2">
            Gestão & Sincronia
          </p>
        </div>

        <form onSubmit={handleAuth} className="space-y-5 relative">
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-2">Identificação</label>
            <div className="relative">
              <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="email"
                required
                value={email}
                onChange={e => setEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/5 rounded-3xl py-4.5 pl-14 pr-6 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600 text-sm"
                placeholder="seu@email.com"
              />
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-2">Senha Segura</label>
            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="password"
                required
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/5 rounded-3xl py-4.5 pl-14 pr-6 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600 text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          {!isRegistering && (
            <div className="flex items-center justify-between px-2">
              <button type="button" onClick={() => setRememberMe(!rememberMe)} className="flex items-center gap-2 text-[11px] font-bold text-slate-500 hover:text-slate-300 transition-colors">
                {rememberMe ? <CheckCircle2 size={16} className="text-blue-500" /> : <Circle size={16} />}
                Lembrar neste aparelho
              </button>
            </div>
          )}

          {error && <p className="text-red-400 text-[10px] font-black text-center bg-red-500/10 py-3 rounded-2xl border border-red-500/10 uppercase tracking-widest">{error}</p>}

          <button type="submit" className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 py-5 rounded-[24px] font-black text-white shadow-2xl shadow-blue-500/20 active:scale-[0.98] transition-all flex items-center justify-center gap-3">
            {isRegistering ? <UserPlus size={20} /> : <LogIn size={20} />}
            {isRegistering ? 'CRIAR MINHA CONTA' : 'ACESSAR AGORA'}
          </button>
        </form>

        <div className="mt-8 flex flex-col items-center gap-4 relative">
          <button onClick={() => setIsRegistering(!isRegistering)} className="text-slate-500 hover:text-blue-400 text-[11px] font-black uppercase tracking-widest transition-colors">
            {isRegistering ? 'Já possui conta? Entrar' : 'Não possui conta? Cadastrar'}
          </button>

          <div className="pt-6 border-t border-white/5 w-full flex items-center justify-center gap-3 opacity-40">
            <Smartphone size={14} className="text-slate-500" />
            <span className="text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">Multi-Device v2.0</span>
          </div>
        </div>
      </div>
    </div>
  );
};

