            setServices(data.services);
          }
          alert('Dados sincronizados!');
        }
      } catch (e) {
        alert('Arquivo inválido.');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  if (!user) return <Login onLogin={handleLogin} />;

