interface ServiceListProps {
  services: ServiceRecord[];
  onDelete: (id: string) => void;
}

const ServiceList: React.FC<ServiceListProps> = ({ services, onDelete }) => {
  const grouped = services.reduce((acc: MonthlyGroup[], curr) => {
    const date = new Date(curr.date);
    const monthYear = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

    let group = acc.find(g => g.monthYear === monthYear);
    if (!group) {
      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }
    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date).getTime();
    const dateB = new Date(b.services[0].date).getTime();
    return dateB - dateA;
  });

  return (
    <div className="space-y-10">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-4">
          <div className="flex items-center justify-between sticky top-[72px] bg-[#020617]/95 backdrop-blur-sm py-2 z-30">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-blue-400 flex items-center gap-2">
              <CalendarDays size={14} />
              {group.monthYear}
            </h3>
          </div>

          <div className="grid grid-cols-1 gap-3">
            {group.services.map(service => (
              <div key={service.id} className="bg-slate-900/40 border border-white/5 rounded-3xl p-5 shadow-sm active:bg-slate-800/40 transition-colors">
                <div className="flex justify-between items-start gap-4">
                  <div className="space-y-2 flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-blue-500 text-[9px] font-black uppercase tracking-widest bg-blue-500/10 px-2 py-0.5 rounded-lg border border-blue-500/10">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-slate-500 text-[9px] font-bold bg-white/5 px-2 py-0.5 rounded-lg uppercase">
                        {service.paymentMethod}
                      </span>
                    </div>
                    <h4 className="font-bold text-white text-base truncate">{service.clientName}</h4>
                    <p className="text-xs text-slate-500 italic line-clamp-2">{service.description}</p>
                  </div>
                  <div className="text-right flex flex-col items-end gap-4 shrink-0">
