                      {service.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>
                    <button 
                      onClick={(e) => {
                        e.stopPropagation();
                        onDelete(service.id);
                      }} 
                      className="p-3 text-slate-500 hover:text-red-400 transition-colors bg-white/5 hover:bg-red-500/10 rounded-2xl border border-white/5 active:scale-90"
                      aria-label="Excluir serviço"
