import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Mail, CloudUpload, Filter, Briefcase, Share2, Info } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_pro_v10_data';
const AUTH_KEY = 'service_pro_v10_auth';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return [];
  });

  const [user, setUser] = useState<User | null>(() => {
    try {
      const savedAuth = localStorage.getItem(AUTH_KEY);
      if (savedAuth) return JSON.parse(savedAuth);
    } catch (e) {}
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [showSyncInfo, setShowSyncInfo] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { id: 'user-' + Date.now(), username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da conta?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService = { ...data, id: 'srv-' + Math.random().toString(36).substr(2, 9) + Date.now() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setServices(prev => {
        const filtered = prev.filter(s => s.id !== id);
        return [...filtered];
      });
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [services]);

  const handleSyncEmail = async () => {
    if (services.length === 0) return alert('Não há dados para sincronizar.');

    try {
      // 1. Gerar Excel para backup formal
      const ws = XLSX.utils.json_to_sheet(services.map(s => ({
        Data: new Date(s.date).toLocaleDateString('pt-BR'),
        Cliente: s.clientName,
        Serviço: s.description,
        Valor: s.value,
        Pagamento: s.paymentMethod
      })));
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Serviços");
      XLSX.writeFile(wb, `Relatorio_Servicos.xlsx`);

      // 2. Gerar arquivo JSON de Sincronia
      const syncData = JSON.stringify({ services, timestamp: new Date().toISOString() });
      const blob = new Blob([syncData], { type: 'application/json' });
      const fileName = `Sincronia_ServiceApp.json`;

      // 3. Tentar Compartilhamento Nativo (WhatsApp/Email no celular)
      if (navigator.share) {
        const file = new File([blob], fileName, { type: 'application/json' });
        try {
          await navigator.share({
            title: 'Sincronização Service App',
            text: 'Dados para sincronizar com outro dispositivo.',
            files: [file]
          });
        } catch (e) {
          downloadFile(syncData, fileName);
        }
      } else {
        downloadFile(syncData, fileName);
      }

      // 4. Fluxo de E-mail solicitado
      const email = 'layannefranca1@gmail.com';
      const subject = encodeURIComponent('Sincronização de Dados - Service App');
      const body = encodeURIComponent(`Olá!\n\nEstou enviando os dados de serviços para sincronizar o outro aparelho.\n\nTotal Acumulado: R$ ${totalAccumulated.toFixed(2)}\nTotal de Serviços: ${services.length}\n\nINSTRUÇÕES:\n1. Baixe o arquivo .json em anexo (ou enviado) no outro celular.\n2. No App do outro celular, clique no ícone de "Nuvem com Seta" (Importar).\n3. Selecione o arquivo baixado.`);

      window.location.href = `mailto:${email}?subject=${subject}&body=${body}`;

    } catch (err) {
      alert("Erro ao preparar sincronização.");
    }
  };

  const downloadFile = (content: string, name: string) => {
    const blob = new Blob([content], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = name;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target?.result as string);
        if (data && Array.isArray(data.services)) {
          if (window.confirm(`Deseja importar ${data.services.length} serviços e somar aos que você já tem?`)) {
            setServices(prev => {
              const existingIds = new Set(prev.map(s => s.id));
              const news = data.services.filter((s: any) => !existingIds.has(s.id));
              return [...news, ...prev];
            });
            alert('Sincronização via arquivo concluída!');
          }
        }
      } catch (e) {
        alert('Este arquivo não é um backup válido do Service App.');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/90 backdrop-blur-xl border-b border-white/5 p-4 shadow-xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-tr from-blue-600 to-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Briefcase size={20} className="text-white" />
            </div>
            <div>
              <h1 className="text-base font-black tracking-tight leading-none uppercase">Service App</h1>
              <p className="text-[8px] text-blue-400 font-bold uppercase tracking-widest mt-1">Sincronia layannefranca1@gmail.com</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleSyncEmail} title="Sincronizar via E-mail" className="p-2.5 bg-blue-600 text-white rounded-xl shadow-lg shadow-blue-600/20 active:scale-90 transition-transform">
              <Mail size={18} />
            </button>
            <button onClick={() => fileInputRef.current?.click()} title="Importar Backup" className="p-2.5 bg-emerald-500/10 text-emerald-500 rounded-xl border border-emerald-500/20 active:scale-90 transition-transform">
              <CloudUpload size={18} />
            </button>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
            <button onClick={handleLogout} className="p-2.5 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 active:scale-90 transition-transform">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <DashboardStats total={totalAccumulated} count={services.length} />

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <Filter size={12} className="text-blue-500" />
              Relatório Mensal
            </h2>
            <button onClick={() => setShowSyncInfo(true)} className="text-[9px] font-bold text-blue-400 uppercase tracking-widest bg-blue-400/10 px-3 py-1 rounded-full">Como Sincronizar?</button>
          </div>

          {services.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 bg-slate-900/30 border border-white/5 border-dashed rounded-[48px] text-slate-700">
              <Plus size={32} className="mb-4 opacity-10" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Nenhum Serviço Cadastrado</p>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      {showSyncInfo && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-[#020617]/95 backdrop-blur-md" onClick={() => setShowSyncInfo(false)}>
          <div className="bg-slate-900 border border-white/10 p-8 rounded-[40px] max-w-sm w-full shadow-3xl text-center space-y-6" onClick={e => e.stopPropagation()}>
            <div className="w-16 h-16 bg-blue-600/10 rounded-full flex items-center justify-center mx-auto text-blue-500">
              <Mail size={28} />
            </div>
            <div className="space-y-4">
              <h3 className="text-lg font-bold">Sincronia Multi-Aparelho</h3>
              <p className="text-slate-400 text-[11px] leading-relaxed text-left">
                Como não usamos um servidor central por segurança:<br/><br/>
                1. No celular 1, clique no <strong>Botão de E-mail (Azul)</strong>.<br/>
                2. Envie o e-mail para você mesma.<br/>
                3. No celular 2, abra o e-mail, baixe o arquivo .json.<br/>
                4. No App do celular 2, clique na <strong>Nuvem (Verde)</strong> e escolha o arquivo baixado.
              </p>
            </div>
            <button onClick={() => setShowSyncInfo(false)} className="w-full bg-blue-600 py-4 rounded-2xl font-bold active:scale-95 transition-transform">Entendi</button>
          </div>
        </div>
      )}

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[24px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-4 ring-[#020617]"
      >
        <Plus size={32} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

