  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const isAdmin = username.toLowerCase() === ADMIN_EMAIL.toLowerCase();
    const newUser = { 
      id: 'user-' + Date.now(), 
      username, 
      isAuthenticated: true,
      isAdmin 
    };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair da conta?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService: ServiceRecord = { 
      ...data, 
      id: 'srv-' + Math.random().toString(36).substr(2, 9) + Date.now(),
      ownerEmail: user?.username 
    };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir permanentemente?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  // Lista de usuários únicos para o filtro do ADM
  const uniqueUsers = useMemo(() => {
    const emails = services.map(s => s.ownerEmail).filter(Boolean) as string[];
    return Array.from(new Set(emails));
  }, [services]);

  // Filtragem dos serviços conforme seleção do ADM
  const filteredServices = useMemo(() => {
    if (!user?.isAdmin || filterUser === 'all') return services;
    return services.filter(s => s.ownerEmail === filterUser);
  }, [services, filterUser, user]);

  const totalAccumulated = useMemo(() => {
    return filteredServices.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [filteredServices]);

  const handleSyncEmail = async () => {
    if (services.length === 0) return alert('Sem dados.');
    const myServices = services.filter(s => s.ownerEmail === user?.username);

    try {
      const syncData = JSON.stringify({ 
        services: myServices, 
        sourceUser: user?.username,
        timestamp: new Date().toISOString() 
      });
      const blob = new Blob([syncData], { type: 'application/json' });
      const fileName = `Backup_${user?.username?.split('@')[0]}.json`;

      if (navigator.share) {
        await navigator.share({
          title: 'Dados de Serviço',
          files: [new File([blob], fileName, { type: 'application/json' })]
        });
      } else {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = fileName;
        a.click();
      }

      window.location.href = `mailto:${ADMIN_EMAIL}?subject=Dados de Serviço - ${user?.username}&body=Arquivo de sincronia em anexo.`;
    } catch (err) {}
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target?.result as string);
        if (data && Array.isArray(data.services)) {
          const source = data.sourceUser || 'Desconhecido';
          const msg = user?.isAdmin 
            ? `Deseja importar os dados de ${source}?\nEstes dados serão adicionados à sua base de visualização.`
            : `Deseja mesclar estes serviços aos seus atuais?`;

          if (window.confirm(msg)) {
            setServices(prev => {
              const existingIds = new Set(prev.map(s => s.id));
              const news = data.services.map((s: any) => ({
                ...s,
                ownerEmail: s.ownerEmail || source // Garante que tem um dono
              })).filter((s: any) => !existingIds.has(s.id));
              return [...news, ...prev];
            });
            alert('Importação concluída!');
          }
        }
      } catch (e) {
        alert('Erro ao ler backup.');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans">
      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shadow-lg ${user.isAdmin ? 'bg-amber-500 shadow-amber-500/20' : 'bg-blue-600 shadow-blue-500/20'}`}>
              {user.isAdmin ? <ShieldCheck size={20} /> : <Briefcase size={20} />}
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tight uppercase leading-none">
                {user.isAdmin ? 'Painel Admin' : 'Meus Serviços'}
              </h1>
              <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mt-1 truncate max-w-[120px]">
                {user.username}
              </p>
            </div>
          </div>

          <div className="flex gap-2">
            {user.isAdmin && uniqueUsers.length > 0 && (
              <div className="relative">
                <select 
                  value={filterUser}
                  onChange={(e) => setFilterUser(e.target.value)}
                  className="appearance-none bg-slate-800 border border-white/10 rounded-xl px-3 py-2.5 text-[10px] font-bold uppercase tracking-widest pr-8 outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="all">Todos Usuários</option>
                  {uniqueUsers.map(email => (
                    <option key={email} value={email}>{email.split('@')[0]}</option>
                  ))}
                </select>
                <Filter size={12} className="absolute right-2.5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500" />
              </div>
            )}
            <button onClick={handleSyncEmail} className="p-2.5 bg-blue-600 text-white rounded-xl shadow-lg active:scale-90 transition-transform">
              <Mail size={18} />
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="p-2.5 bg-emerald-500/10 text-emerald-500 rounded-xl border border-emerald-500/20 active:scale-90">
              <CloudUpload size={18} />
            </button>
            <input type="file" ref={fileInputRef} onChange={handleImport} accept=".json" className="hidden" />
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-500">
        <DashboardStats 
          total={totalAccumulated} 
          count={filteredServices.length} 
          subtitle={filterUser === 'all' ? "Consolidado Geral" : `Dados de ${filterUser.split('@')[0]}`}
        />

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <Users size={12} className="text-blue-500" />
              {user.isAdmin ? 'Relatórios de Equipe' : 'Meu Histórico'}
            </h2>
          </div>

          {filteredServices.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 bg-slate-900/30 border border-white/5 rounded-[40px] text-slate-600">
              <p className="text-[10px] font-black uppercase tracking-widest">Nenhum dado encontrado</p>
            </div>
          ) : (
            <ServiceList 
              services={filteredServices} 
              onDelete={deleteService} 
              showOwner={user.isAdmin && filterUser === 'all'} 
            />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-3xl flex items-center justify-center shadow-2xl active:scale-90 hover:scale-110 transition-all z-50"
      >
        <Plus size={32} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

