import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Mail, CloudUpload, Filter, Briefcase, Share2, Info, Users, ShieldCheck, Globe, RefreshCw, CheckCircle2 } from 'lucide-react';
import * as XLSX from 'xlsx';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_pro_cloud_v12_data';
const AUTH_KEY = 'service_pro_cloud_v12_auth';
const ADMIN_EMAIL = 'layannefranca1@gmail.com';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return [];
  });

  const [user, setUser] = useState<User | null>(() => {
    try {
      const savedAuth = localStorage.getItem(AUTH_KEY);
      if (savedAuth) return JSON.parse(savedAuth);
    } catch (e) {}
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const [filterUser, setFilterUser] = useState<string>('all');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Simulação de Sincronia com Banco de Dados
  useEffect(() => {
    if (user) {
      setIsSyncing(true);
      const timer = setTimeout(() => {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
        setIsSyncing(false);
        setLastSync(new Date().toLocaleTimeString());
      }, 800);
      return () => clearTimeout(timer);
    }
  }, [services, user]);

  const handleLogin = (username: string) => {
    const isAdmin = username.toLowerCase() === ADMIN_EMAIL.toLowerCase();
    const newUser = { 
      id: 'user-' + Date.now(), 
      username, 
      isAuthenticated: true,
      isAdmin 
    };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja encerrar a sessão cloud?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService: ServiceRecord = { 
      ...data, 
      id: 'srv-' + Math.random().toString(36).substr(2, 9) + Date.now(),
      ownerEmail: user?.username 
    };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir do banco de dados permanentemente?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const uniqueUsers = useMemo(() => {
    const emails = services.map(s => s.ownerEmail).filter(Boolean) as string[];
    return Array.from(new Set(emails));
  }, [services]);

  const filteredServices = useMemo(() => {
    if (!user?.isAdmin || filterUser === 'all') return services;
    return services.filter(s => s.ownerEmail === filterUser);
  }, [services, filterUser, user]);

  const totalAccumulated = useMemo(() => {
    return filteredServices.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [filteredServices]);

  const forceSync = () => {
    setIsSyncing(true);
    setTimeout(() => {
      setIsSyncing(false);
      setLastSync(new Date().toLocaleTimeString());
      alert("Sincronia com o servidor concluída com sucesso!");
    }, 1500);
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      {/* Cloud Status Bar */}
