          </div>
        ) : (
          <div className="flex items-center gap-2">
            <CheckCircle2 size={10} className="text-emerald-500" />
            <span className="text-[9px] font-black uppercase tracking-widest text-emerald-500">Banco de Dados Online • Última sincronia: {lastSync}</span>
          </div>
        )}
      </div>

      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-11 h-11 rounded-2xl flex items-center justify-center shadow-lg transition-all ${user.isAdmin ? 'bg-amber-500 shadow-amber-500/20' : 'bg-blue-600 shadow-blue-500/20'}`}>
              {user.isAdmin ? <ShieldCheck size={22} /> : <Globe size={22} />}
            </div>
            <div className="hidden xs:block">
              <h1 className="text-sm font-black tracking-tight uppercase leading-none flex items-center gap-2">
                {user.isAdmin ? 'Central ADM' : 'Service Cloud'}
