              </h1>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest mt-1 truncate max-w-[150px]">
                Conta: {user.username}
              </p>
            </div>
          </div>

          <div className="flex gap-2">
            {user.isAdmin && (
              <div className="relative group">
                <select 
                  value={filterUser}
                  onChange={(e) => setFilterUser(e.target.value)}
                  className="appearance-none bg-slate-800 border border-white/10 rounded-xl px-4 py-3 text-[10px] font-bold uppercase tracking-widest pr-10 outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                >
                  <option value="all">Rede Global</option>
                  {uniqueUsers.map(email => (
                    <option key={email} value={email}>{email.split('@')[0]}</option>
                  ))}
                </select>
                <Users size={12} className="absolute right-3.5 top-1/2 -translate-y-1/2 pointer-events-none text-slate-500" />
