              <RefreshCw size={18} className={isSyncing ? 'animate-spin' : ''} />
            </button>

            <button onClick={handleLogout} className="p-3 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 active:scale-90 transition-all">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-700">
        <DashboardStats 
          total={totalAccumulated} 
          count={filteredServices.length} 
          subtitle={filterUser === 'all' ? "Faturamento da Rede" : `Produtividade: ${filterUser.split('@')[0]}`}
        />

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></div>
              {user.isAdmin ? 'Monitoramento de Serviços' : 'Meus Lançamentos'}
            </h2>
          </div>

          {filteredServices.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 bg-slate-900/20 border border-white/5 border-dashed rounded-[48px] text-slate-700">
              <CloudUpload size={40} className="mb-4 opacity-10" />
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Aguardando dados da nuvem...</p>
            </div>
          ) : (
            <ServiceList 
              services={filteredServices} 
              onDelete={deleteService} 
              showOwner={user.isAdmin && filterUser === 'all'} 
            />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[28px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-4 ring-[#020617]"
      >
        <Plus size={32} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Mail, Lock, UserPlus, LogIn, CheckCircle2, Circle, Smartphone, Globe } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
}

const USERS_KEY = 'service_app_users_v6';
const REMEMBER_KEY = 'service_app_remember_v6';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(REMEMBER_KEY);
      if (saved) {
        const { e, p } = JSON.parse(saved);
        setEmail(e);
        setPassword(p);
        setRememberMe(true);
      }
    } catch (e) {}
  }, []);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Simulação de latência de rede/banco de dados
    setTimeout(() => {
      try {
        const savedUsers = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
        const defaultUser = { email: 'layannefranca1@gmail.com', password: '123' };
        const allUsers = [defaultUser, ...savedUsers];

        if (isRegistering) {
          if (allUsers.find((u: any) => u.email === email)) {
