import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Briefcase, Download, Trash2, CalendarDays } from 'lucide-react';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';

const STORAGE_KEY = 'service_pro_local_v1';
const AUTH_KEY = 'service_pro_auth_v1';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return [];
  });

  const [user, setUser] = useState<User | null>(() => {
    try {
      const savedAuth = localStorage.getItem(AUTH_KEY);
      if (savedAuth) return JSON.parse(savedAuth);
    } catch (e) {}
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const handleLogin = (username: string) => {
    const newUser = { 
      id: 'user-' + Date.now(), 
      username, 
      isAuthenticated: true
    };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair do aplicativo?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService: ServiceRecord = { 
      ...data, 
      id: 'srv-' + Math.random().toString(36).substr(2, 9) + Date.now()
    };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    if (window.confirm('Excluir este serviço permanentemente?')) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => {
    return services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0);
  }, [services]);

  const exportData = () => {
    const dataStr = JSON.stringify({ services, exportDate: new Date().toISOString() });
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
    const exportFileDefaultName = `meus_servicos_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  if (!user) return <Login onLogin={handleLogin} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 rounded-2xl bg-blue-600 shadow-lg shadow-blue-500/20 flex items-center justify-center">
              <Briefcase size={22} />
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tight uppercase leading-none">
                Service App
              </h1>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest mt-1 truncate max-w-[150px]">
                {user.username}
              </p>
            </div>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={exportData}
              className="p-3 bg-slate-800 text-slate-300 rounded-xl border border-white/5 active:scale-90 transition-all hover:bg-slate-700"
              title="Exportar Backup"
            >
              <Download size={18} />
            </button>

            <button onClick={handleLogout} className="p-3 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 active:scale-90 transition-all">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-700">
        <DashboardStats 
          total={totalAccumulated} 
          count={services.length} 
        />

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
              Histórico de Lançamentos
            </h2>
          </div>

          {services.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-24 bg-slate-900/20 border border-white/5 border-dashed rounded-[48px] text-slate-700">
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Nenhum serviço cadastrado</p>
            </div>
          ) : (
            <ServiceList 
              services={services} 
              onDelete={deleteService} 
            />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[28px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-4 ring-[#020617]"
      >
        <Plus size={32} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React from 'react';
import { Trash2, CalendarDays, Wallet } from 'lucide-react';
import { ServiceRecord, MonthlyGroup } from '../types';

interface ServiceListProps {
  services: ServiceRecord[];
  onDelete: (id: string) => void;
}

const ServiceList: React.FC<ServiceListProps> = ({ services, onDelete }) => {
  const grouped = services.reduce((acc: MonthlyGroup[], curr) => {
    const date = new Date(curr.date);
    const monthYear = date.toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });

    let group = acc.find(g => g.monthYear === monthYear);
    if (!group) {
      group = { monthYear, services: [], totalValue: 0 };
      acc.push(group);
    }
    group.services.push(curr);
    group.totalValue += curr.value;
    return acc;
  }, []);

  const sortedGroups = [...grouped].sort((a, b) => {
    const dateA = new Date(a.services[0].date).getTime();
    const dateB = new Date(b.services[0].date).getTime();
    return dateB - dateA;
  });

  return (
    <div className="space-y-12">
      {sortedGroups.map(group => (
        <div key={group.monthYear} className="space-y-4">
          <div className="flex items-center justify-between sticky top-[72px] bg-[#020617]/95 backdrop-blur-md py-3 z-30">
            <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400 flex items-center gap-2">
              <CalendarDays size={14} className="opacity-50" />
              {group.monthYear}
            </h3>
            <div className="h-[1px] flex-1 mx-4 bg-white/5"></div>
          </div>

          <div className="grid grid-cols-1 gap-4">
            {group.services.map(service => (
              <div key={service.id} className="group relative bg-slate-900/40 border border-white/5 rounded-[32px] p-6 transition-all active:bg-slate-800/60 overflow-hidden">
                <div className="flex justify-between items-start gap-4">
                  <div className="space-y-3 flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-blue-500 text-[9px] font-black uppercase tracking-widest bg-blue-500/10 px-2.5 py-1 rounded-lg border border-blue-500/10">
                        {new Date(service.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="text-slate-500 text-[9px] font-bold bg-white/5 px-2.5 py-1 rounded-lg uppercase tracking-wider flex items-center gap-1">
                        <Wallet size={10} />
                        {service.paymentMethod}
                      </span>
                    </div>
                    <div>
                      <h4 className="font-bold text-white text-lg truncate mb-1">{service.clientName}</h4>
                      <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed opacity-70 italic">"{service.description}"</p>
                    </div>
                  </div>

                  <div className="flex flex-col items-end justify-between h-full min-h-[80px]">
                    <p className="text-xl font-black text-white tracking-tighter">
                      {service.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                    </p>

                    <button 
                      type="button"
                      onClick={(e) => {
                        e.preventDefault();
                        e.stopPropagation();
                        onDelete(service.id);
                      }} 
                      className="mt-4 p-3.5 text-slate-500 hover:text-red-400 transition-all bg-white/5 hover:bg-red-500/10 rounded-2xl border border-white/5 active:scale-75 shadow-lg"
                      aria-label="Excluir"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="bg-gradient-to-r from-emerald-500/10 to-transparent border-l-4 border-emerald-500 p-5 rounded-r-[32px] flex items-center justify-between shadow-inner">
            <span className="text-[10px] font-black text-emerald-500 uppercase tracking-[0.2em]">Total do Mês:</span>
            <span className="text-2xl font-black text-emerald-400 tracking-tighter">
              {group.totalValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
            </span>
          </div>
        </div>
      ))}
    </div>
  );
};

