const AUTH_KEY = 'service_pro_auth_v1';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) return JSON.parse(saved);
    } catch (e) {}
    return [];
  });

  const [user, setUser] = useState<User | null>(() => {
    try {
      const savedAuth = localStorage.getItem(AUTH_KEY);
      if (savedAuth) return JSON.parse(savedAuth);
    } catch (e) {}
    return null;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  useEffect(() => {
    window.addEventListener('beforeinstallprompt', (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    });
  }, []);

  const handleInstall = async () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') setDeferredPrompt(null);
    } else {
      alert('Para instalar:\n\nNo Android: 3 pontinhos > Instalar App.\n\nNo iPhone: Compartilhar > Adicionar à Tela de Início.');
    }
  };

  const handleLogin = (username: string) => {
    const newUser = { id: 'user-' + Date.now(), username, isAuthenticated: true };
    setUser(newUser);
    localStorage.setItem(AUTH_KEY, JSON.stringify(newUser));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja sair?')) {
      setUser(null);
      localStorage.removeItem(AUTH_KEY);
    }
  };

  const addService = (data: Omit<ServiceRecord, 'id'>) => {
    const newService: ServiceRecord = { ...data, id: 'srv-' + Math.random().toString(36).substr(2, 9) + Date.now() };
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);
  };

  const deleteService = (id: string) => {
    const service = services.find(s => s.id === id);
    if (window.confirm(`Tem certeza que deseja excluir o serviço para "${service?.clientName || 'este cliente'}"? Esta ação não pode ser desfeita.`)) {
      setServices(prev => prev.filter(s => s.id !== id));
    }
  };

  const totalAccumulated = useMemo(() => services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0), [services]);

