  const exportAndShare = async () => {
    const dataStr = JSON.stringify({ services, exportDate: new Date().toISOString() }, null, 2);
    const fileName = `backup_servicos_${new Date().toISOString().split('T')[0]}.json`;

    if (navigator.share) {
      try {
        const file = new File([dataStr], fileName, { type: 'application/json' });
