    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
