            <button onClick={handleInstall} className="p-3 bg-slate-800/50 text-slate-400 rounded-xl border border-white/5 active:scale-90 transition-all">
              <Smartphone size={18} />
            </button>

            {/* Importar (Sincronizar de volta) */}
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="p-3 bg-emerald-500/10 text-emerald-400 rounded-xl border border-emerald-500/10 active:scale-90 transition-all"
              title="Importar do E-mail"
            >
              <Upload size={18} />
