export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Briefcase, RefreshCw, Smartphone, Trash2, CalendarDays, Share2, Cloud, CloudOff } from 'lucide-react';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';
import { supabase } from './lib/supabase';

const STORAGE_KEY = 'service_pro_local_v1';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  const [user, setUser] = useState<any | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [online, setOnline] = useState(navigator.onLine);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Monitorar estado da rede
  useEffect(() => {
    const handleOnline = () => setOnline(true);
    const handleOffline = () => setOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Verificar sessão inicial do Supabase
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });

    return () => subscription.unsubscribe();
  }, []);

  // Buscar serviços do Supabase quando logado
  useEffect(() => {
    if (user && online) {
      fetchServices();
    }
  }, [user, online]);

  // Salvar no localStorage sempre que mudar (Offline-first)
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const fetchServices = async () => {
    if (!user) return;
    setIsSyncing(true);
    const { data, error } = await supabase
      .from('services')
      .select('*')
      .order('date', { ascending: false });

    if (error) {
      console.error('Erro ao buscar dados:', error);
    } else if (data) {
      // Mapear snake_case do banco para camelCase do app
      const mappedData: ServiceRecord[] = data.map(item => ({
        id: item.id,
        clientName: item.client_name,
        description: item.description,
        value: item.value,
        paymentMethod: item.payment_method,
        date: item.date
      }));
      setServices(mappedData);
    }
    setIsSyncing(false);
  };

  const addService = async (data: Omit<ServiceRecord, 'id'>) => {
    const newId = crypto.randomUUID();
    const newService = { ...data, id: newId };

    // Atualiza local primeiro para resposta rápida (Optimistic Update)
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);

    if (user && online) {
      const { error } = await supabase.from('services').insert([{
        id: newId,
        client_name: data.clientName,
        description: data.description,
        value: data.value,
        payment_method: data.paymentMethod,
        date: data.date,
        user_id: user.id
      }]);
      if (error) console.error('Erro ao salvar na nuvem:', error);
    }
  };

  const deleteService = async (id: string) => {
    const serviceToDelete = services.find(s => s.id === id);
    if (!window.confirm(`Excluir serviço de "${serviceToDelete?.clientName}"?`)) return;

    setServices(prev => prev.filter(s => s.id !== id));

    if (user && online) {
      const { error } = await supabase.from('services').delete().eq('id', id);
      if (error) console.error('Erro ao excluir na nuvem:', error);
    }
  };

  const handleLogout = async () => {
    if (window.confirm('Deseja sair da conta?')) {
      await supabase.auth.signOut();
      setServices([]);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  const totalAccumulated = useMemo(() => 
    services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0), 
    [services]
  );

  if (!user) return <Login onLogin={() => {}} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 rounded-2xl bg-blue-600 shadow-lg shadow-blue-500/20 flex items-center justify-center">
              <Briefcase size={22} />
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tight uppercase leading-none">Service App</h1>
              <div className="flex items-center gap-1.5 mt-1">
                {online ? (
                  <Cloud size={10} className={isSyncing ? "text-blue-400 animate-pulse" : "text-emerald-500"} />
                ) : (
                  <CloudOff size={10} className="text-red-500" />
                )}
                <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest truncate max-w-[100px]">
                  {user.email}
                </p>
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={fetchServices}
              disabled={isSyncing || !online}
              className={`p-3 rounded-xl border border-white/5 active:scale-90 transition-all ${isSyncing ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800/50 text-slate-400'}`}
            >
              <RefreshCw size={18} className={isSyncing ? "animate-spin" : ""} />
            </button>

            <button onClick={handleLogout} className="p-3 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 active:scale-90 transition-all">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-700">
        <DashboardStats total={totalAccumulated} count={services.length} />

        {!online && (
          <div className="bg-red-500/10 border border-red-500/20 rounded-2xl p-4 flex items-center gap-3">
            <CloudOff size={18} className="text-red-400" />
            <p className="text-[10px] text-red-200 font-bold uppercase tracking-wider">
              Você está offline. Alterações serão salvas localmente e sincronizadas quando houver conexão.
            </p>
          </div>
        )}

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
              Histórico em Nuvem
            </h2>
          </div>

          {services.length === 0 && !isSyncing ? (
            <div className="flex flex-col items-center justify-center py-24 bg-slate-900/20 border border-white/5 border-dashed rounded-[48px] text-slate-700">
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Nenhum serviço encontrado</p>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[28px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-4 ring-[#020617]"
      >
        <Plus size={32} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Mail, Lock, UserPlus, LogIn, RefreshCw, Briefcase } from 'lucide-react';
import { supabase } from '../lib/supabase';

interface LoginProps {
  onLogin: () => void;
}

const Login: React.FC<LoginProps> = () => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      if (isRegistering) {
        const { error: signUpError } = await supabase.auth.signUp({
          email,
          password,
        });
        if (signUpError) throw signUpError;
        alert('Confirme seu e-mail para ativar a conta!');
        setIsRegistering(false);
      } else {
        const { error: signInError } = await supabase.auth.signInWithPassword({
          email,
          password,
        });
        if (signInError) throw signInError;
      }
    } catch (err: any) {
      setError(err.message || 'Erro ao processar autenticação.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 font-sans">
      <div className="w-full max-w-md bg-slate-900/40 border border-white/5 p-10 rounded-[48px] shadow-3xl relative overflow-hidden backdrop-blur-xl">
        <div className="absolute -top-24 -right-24 w-48 h-48 bg-blue-600/10 blur-[100px] rounded-full"></div>

        <div className="flex flex-col items-center mb-10 relative">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[28px] flex items-center justify-center mb-6 shadow-2xl shadow-blue-500/30 ring-1 ring-white/20">
            <Briefcase size={40} className="text-white" />
          </div>
          <h1 className="text-3xl font-black text-white tracking-tight">Service App</h1>
          <p className="text-blue-500 text-[10px] font-black uppercase tracking-[0.4em] mt-2">
            Sincronizado com a Nuvem
          </p>
        </div>

        <form onSubmit={handleAuth} className="space-y-5 relative">
          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-2">E-mail</label>
            <div className="relative">
              <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="email"
                required
                disabled={loading}
                value={email}
                onChange={e => setEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/5 rounded-3xl py-4.5 pl-14 pr-6 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600 text-sm"
                placeholder="seu@email.com"
              />
            </div>
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-2">Senha</label>
            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
              <input
                type="password"
                required
                disabled={loading}
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/5 rounded-3xl py-4.5 pl-14 pr-6 focus:ring-2 focus:ring-blue-500/50 outline-none transition-all placeholder:text-slate-600 text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          {error && <p className="text-red-400 text-[10px] font-black text-center bg-red-500/10 py-3 rounded-2xl border border-red-500/10 uppercase tracking-widest leading-relaxed">{error}</p>}

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 py-5 rounded-[24px] font-black text-white shadow-2xl shadow-blue-500/20 active:scale-[0.98] transition-all flex items-center justify-center gap-3 disabled:opacity-70"
          >
            {loading ? <RefreshCw size={20} className="animate-spin" /> : isRegistering ? <UserPlus size={20} /> : <LogIn size={20} />}
            {loading ? 'PROCESSANDO...' : isRegistering ? 'CRIAR CONTA' : 'ENTRAR'}
          </button>
        </form>

        <div className="mt-8 flex flex-col items-center gap-4 relative">
          <button 
            disabled={loading}
            onClick={() => setIsRegistering(!isRegistering)} 
            className="text-slate-500 hover:text-blue-400 text-[11px] font-black uppercase tracking-widest transition-colors"
          >
            {isRegistering ? 'Já tem conta? Entrar' : 'Novo por aqui? Criar conta nuvem'}
          </button>
        </div>
      </div>
    </div>
  );
};

