import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Plus, LogOut, Briefcase, RefreshCw, Smartphone, Trash2, CalendarDays, Share2, Cloud, CloudOff, AlertTriangle, Zap } from 'lucide-react';
import { ServiceRecord, User } from './types';
import Login from './components/Login';
import ServiceForm from './components/ServiceForm';
import ServiceList from './components/ServiceList';
import DashboardStats from './components/DashboardStats';
import { supabase, isSupabaseConfigured } from './lib/supabase';

const STORAGE_KEY = 'service_pro_local_v1';

const App: React.FC = () => {
  const [services, setServices] = useState<ServiceRecord[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  const [user, setUser] = useState<any | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isRealtimeActive, setIsRealtimeActive] = useState(false);
  const [online, setOnline] = useState(navigator.onLine);

  // Monitorar estado da rede
  useEffect(() => {
    const handleOnline = () => setOnline(true);
    const handleOffline = () => setOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Verificar sessão inicial e configurar Realtime
  useEffect(() => {
    if (!isSupabaseConfigured || !supabase) {
      const localUser = localStorage.getItem('service_pro_auth_v1');
      if (localUser) setUser(JSON.parse(localUser));
      return;
    }

    // 1. Obter sessão inicial
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
    });

    // 2. Escutar mudanças na autenticação
    const { data: { subscription: authListener } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
    });

    return () => {
      authListener.unsubscribe();
    };
  }, []);

  // 3. Configurar Realtime Sync quando o usuário está logado
  useEffect(() => {
    if (!user || !supabase || !isSupabaseConfigured || !online) {
      setIsRealtimeActive(false);
      return;
    }

    // Criar canal para escutar mudanças na tabela 'services' para o usuário logado
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        {
          event: '*', // Escuta INSERT, UPDATE e DELETE
          schema: 'public',
          table: 'services',
          filter: `user_id=eq.${user.id}`
        },
        (payload) => {
          console.log('Mudança detectada em tempo real:', payload);
          fetchServices(); // Recarrega os dados para garantir consistência total
        }
      )
      .subscribe((status) => {
        setIsRealtimeActive(status === 'SUBSCRIBED');
      });

    // Buscar dados imediatamente ao conectar
    fetchServices();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user, online]);

  // Salvar no localStorage sempre que mudar (Cache Offline)
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(services));
  }, [services]);

  const fetchServices = async () => {
    if (!user || !supabase || !isSupabaseConfigured) return;
    setIsSyncing(true);
    try {
      const { data, error } = await supabase
        .from('services')
        .select('*')
        .eq('user_id', user.id) // Garante que busca apenas os dados deste usuário
        .order('date', { ascending: false });

      if (error) {
        console.error('Erro ao buscar dados:', error);
      } else if (data) {
        const mappedData: ServiceRecord[] = data.map(item => ({
          id: item.id,
          clientName: item.client_name,
          description: item.description,
          value: item.value,
          paymentMethod: item.payment_method,
          date: item.date
        }));
        setServices(mappedData);
      }
    } catch (err) {
      console.error('Falha na sincronização:', err);
    } finally {
      setIsSyncing(false);
    }
  };

  const addService = async (data: Omit<ServiceRecord, 'id'>) => {
    const newId = crypto.randomUUID();
    const newService = { ...data, id: newId };

    // Update otimista (local primeiro para ser instantâneo)
    setServices(prev => [newService, ...prev]);
    setIsFormOpen(false);

    if (user && online && supabase && isSupabaseConfigured) {
      try {
        const { error } = await supabase.from('services').insert([{
          id: newId,
          client_name: data.clientName,
          description: data.description,
          value: data.value,
          payment_method: data.paymentMethod,
          date: data.date,
          user_id: user.id
        }]);
        if (error) {
          console.error('Erro ao salvar na nuvem:', error);
          // O fetchServices do Realtime corrigirá o estado caso o insert falhe
        }
      } catch (err) {
        console.error('Falha ao enviar para nuvem:', err);
      }
    }
  };

  const deleteService = async (id: string) => {
    const serviceToDelete = services.find(s => s.id === id);
    if (!window.confirm(`Excluir serviço de "${serviceToDelete?.clientName}"?`)) return;

    setServices(prev => prev.filter(s => s.id !== id));

    if (user && online && supabase && isSupabaseConfigured) {
      try {
        const { error } = await supabase.from('services').delete().eq('id', id);
        if (error) console.error('Erro ao excluir na nuvem:', error);
      } catch (err) {
        console.error('Falha ao excluir na nuvem:', err);
      }
    }
  };

  const handleLogout = async () => {
    if (window.confirm('Deseja sair da conta?')) {
      if (supabase && isSupabaseConfigured) {
        await supabase.auth.signOut();
      }
      setUser(null);
      setServices([]);
      localStorage.removeItem(STORAGE_KEY);
      localStorage.removeItem('service_pro_auth_v1');
    }
  };

  const totalAccumulated = useMemo(() => 
    services.reduce((acc, curr) => acc + (Number(curr.value) || 0), 0), 
    [services]
  );

  if (!user) return <Login onLogin={() => {}} />;

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-32 font-sans selection:bg-blue-500/30">
      <header className="sticky top-0 z-40 bg-slate-900/95 backdrop-blur-xl border-b border-white/5 p-4 shadow-2xl">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-11 h-11 rounded-2xl bg-blue-600 shadow-lg shadow-blue-500/20 flex items-center justify-center">
              <Briefcase size={22} />
            </div>
            <div>
              <h1 className="text-sm font-black tracking-tight uppercase leading-none">Service App</h1>
              <div className="flex items-center gap-1.5 mt-1">
                {isSupabaseConfigured ? (
                  <div className="flex items-center gap-1.5">
                    {online ? (
                      <Cloud size={10} className={isSyncing ? "text-blue-400 animate-pulse" : "text-emerald-500"} />
                    ) : (
                      <CloudOff size={10} className="text-red-500" />
                    )}
                    {isRealtimeActive && online && (
                      <Zap size={10} className="text-amber-400 fill-amber-400" title="Sincronização em tempo real ativa" />
                    )}
                  </div>
                ) : (
                  <AlertTriangle size={10} className="text-amber-500" />
                )}
                <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest truncate max-w-[100px]">
                  {user.email || 'Modo Local'}
                </p>
              </div>
            </div>
          </div>

          <div className="flex gap-2">
            {isSupabaseConfigured && (
              <button 
                onClick={fetchServices}
                disabled={isSyncing || !online}
                className={`p-3 rounded-xl border border-white/5 active:scale-90 transition-all ${isSyncing ? 'bg-blue-500/20 text-blue-400' : 'bg-slate-800/50 text-slate-400'}`}
                title="Sincronizar Agora"
              >
                <RefreshCw size={18} className={isSyncing ? "animate-spin" : ""} />
              </button>
            )}

            <button onClick={handleLogout} className="p-3 bg-red-500/10 text-red-400 rounded-xl border border-red-500/10 active:scale-90 transition-all">
              <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto p-4 space-y-6 pt-6 animate-in fade-in duration-700">
        <DashboardStats total={totalAccumulated} count={services.length} />

        {isSupabaseConfigured && isRealtimeActive && (
          <div className="bg-emerald-500/5 border border-emerald-500/10 rounded-2xl p-3 flex items-center justify-center gap-2">
             <Zap size={12} className="text-emerald-500 fill-emerald-500 animate-pulse" />
             <p className="text-[9px] text-emerald-500/80 font-black uppercase tracking-[0.2em]">
               Live Sync Ativo: Dispositivos Conectados
             </p>
          </div>
        )}

        {!isSupabaseConfigured && (
          <div className="bg-amber-500/10 border border-amber-500/20 rounded-2xl p-4 flex flex-col gap-2">
            <div className="flex items-center gap-3 text-amber-400">
              <AlertTriangle size={18} />
              <p className="text-[10px] font-bold uppercase tracking-wider">Supabase não configurado</p>
            </div>
          </div>
        )}

        <div className="space-y-4">
          <div className="flex items-center justify-between px-2">
            <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
              {isSupabaseConfigured ? 'Histórico em Nuvem' : 'Histórico Local'}
            </h2>
          </div>

          {services.length === 0 && !isSyncing ? (
            <div className="flex flex-col items-center justify-center py-24 bg-slate-900/20 border border-white/5 border-dashed rounded-[48px] text-slate-700">
              <p className="text-[10px] font-black uppercase tracking-[0.3em]">Nenhum serviço encontrado</p>
            </div>
          ) : (
            <ServiceList services={services} onDelete={deleteService} />
          )}
        </div>
      </main>

      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-8 right-6 w-16 h-16 bg-gradient-to-tr from-blue-600 to-indigo-600 text-white rounded-[28px] flex items-center justify-center shadow-2xl shadow-blue-500/40 active:scale-90 hover:scale-110 transition-all z-50 ring-4 ring-[#020617]"
      >
        <Plus size={32} strokeWidth={2.5} />
      </button>

      {isFormOpen && <ServiceForm onClose={() => setIsFormOpen(false)} onSubmit={addService} />}
    </div>
  );
};

export default App;

